const DBAS_POOL_WORKER_SOURCE="\nimportScripts('{LIB_URL}');\n\nlet dbPtr = null;\nlet lockName = null;\n\nasync function initialize(msg) {\n    lockName = msg.lockName;\n    const module = await initPersistentFS(msg.dbName, { opfsMode: 'readwrite-unsafe' });\n    dbPtr = module.openDb();\n    if (!module.isOpened(dbPtr)) {\n        throw new Error('Reader failed to open database: ' + module.getLastDbError(dbPtr));\n    }\n    var jmRc = module.executeSql(dbPtr, 'PRAGMA journal_mode=OFF');\n    if (jmRc !== 0) throw new Error('Reader failed to set journal_mode=OFF: ' + module.getLastDbError(dbPtr));\n    var qoRc = module.executeSql(dbPtr, 'PRAGMA query_only=ON');\n    if (qoRc !== 0) throw new Error('Reader failed to set query_only=ON: ' + module.getLastDbError(dbPtr));\n    return { ready: true };\n}\n\nfunction executeQuery(sql, params) {\n    const module = globalThis.DbasSqliteWrapper;\n    if (module.prepareQuery(dbPtr, sql) !== 0) throw new Error(module.getLastDbError(dbPtr));\n    if (params && Array.isArray(params) && params.length > 0) {\n        for (let i = 0; i < params.length; i++) {\n            const v = params[i], idx = i + 1;\n            if (v === null || v === undefined) module.bindNull(dbPtr, idx);\n            else if (typeof v === 'number')\n                Number.isInteger(v) ? module.bindInt(dbPtr, idx, v) : module.bindDouble(dbPtr, idx, v);\n            else module.bindText(dbPtr, idx, String(v));\n        }\n    } else if (params && !Array.isArray(params) && Object.keys(params).length > 0) {\n        for (const [name, v] of Object.entries(params)) {\n            if (v === null || v === undefined) module.bindNameNull(dbPtr, name);\n            else if (typeof v === 'number')\n                Number.isInteger(v) ? module.bindNameInt(dbPtr, name, v) : module.bindNameDouble(dbPtr, name, v);\n            else module.bindNameText(dbPtr, name, String(v));\n        }\n    }\n    const rows = [];\n    while (module.readRow(dbPtr) === 100) {\n        const colCount = module.getColumnCount(dbPtr);\n        const row = {};\n        for (let i = 0; i < colCount; i++) {\n            const name = module.getColumnName(dbPtr, i);\n            const type = module.getColumnType(dbPtr, i);\n            if (type === 1) row[name] = module.getColumnInt(dbPtr, i);\n            else if (type === 2) row[name] = module.getColumnDouble(dbPtr, i);\n            else if (type === 4) row[name] = module.getColumnBlob(dbPtr, i);\n            else if (type === 5) row[name] = null;\n            else row[name] = module.getColumnText(dbPtr, i);\n        }\n        rows.push(row);\n    }\n    module.closeReader(dbPtr);\n    return rows;\n}\n\nself.onmessage = async function(e) {\n    const { id, action, payload } = e.data;\n    try {\n        let result;\n        switch (action) {\n            case 'init':\n                result = await initialize(payload);\n                break;\n            case 'query':\n                if (!lockName || !dbPtr) throw new Error('Reader worker not initialized');\n                result = await navigator.locks.request(lockName, { mode: 'shared' }, async () => {\n                    return executeQuery(payload.sql, payload.params);\n                });\n                break;\n            case 'close':\n                if (dbPtr) {\n                    var mod = globalThis.DbasSqliteWrapper;\n                    mod.closeDb(dbPtr);\n                    dbPtr = null;\n                    mod.closeOpfsHandles();\n                }\n                result = { success: true };\n                break;\n            default:\n                throw new Error('Unknown pool worker action: ' + action);\n        }\n        self.postMessage({ id, result });\n    } catch (error) {\n        self.postMessage({ id, error: error.message });\n    }\n};\n";
// END src/web/dbas_sqlite_pool_worker.js

