"undefined"!=typeof DbasSqlite?globalThis.DbasSqlite=DbasSqlite:console.error("❌ DbasSqlite is not defined"),"undefined"!=typeof DbasSqliteWrapper?globalThis.DbasSqliteWrapper=new DbasSqliteWrapper:console.error("❌ DbasSqliteWrapper is not defined"),globalThis.initPersistentFS=async function(e="dbas.db",a={}){const l=globalThis.DbasSqliteWrapper;return await l.initialize(e,a),l},globalThis.dropDb=()=>globalThis.DbasSqliteWrapper.dropDb(),globalThis.isFsAvailable=()=>globalThis.DbasSqliteWrapper.isFsAvailable(),globalThis.isWorkerPoolSupported=()=>DbasSqliteWrapper.isWorkerPoolSupported(),globalThis.createSharedPool=e=>globalThis.DbasSqliteWrapper.createSharedPool(e);
